for folder, data in updates.items():
    path = os.path.join(base, folder, "rapidapi-listing.json")
    with open(path, 'r', encoding='utf-8') as f:
        listing = json.load(f)

    listing["tags"] = data["tags"]
    listing["category"] = data["category"]
    listing["long_description"] = data["long_description"]

    if "longDescription" in listing:
        listing["longDescription"] = data["long_description"]

    with open(path, 'w', encoding='utf-8') as f:
        json.dump(listing, f, indent=2, ensure_ascii=False)

    print(f"Updated: {folder}")

print(f"\nDone! Updated {len(updates)} APIs.")
